// Example: idempotent meeting create (Node/Express pseudo‑code)
const express = require('express');
const redis = require('redis');
const { v4: uuidv4 } = require('uuid');
const app = express();
const client = redis.createClient();

app.post('/v1/meetings', async (req, res) => {
  const idempotencyKey = req.header('Idempotency-Key') || uuidv4();
  const cacheKey = `meeting:create:${idempotencyKey}`;

  // Try to get cached result (quick path for retries)
  const cached = await client.getAsync(cacheKey);
  if (cached) return res.json(JSON.parse(cached));

  // Use a short lock TTL to prevent thundering retries
  const lock = await client.setAsync(`lock:${cacheKey}`, '1', 'NX', 'PX', 5000);
  if (!lock) return res.status(202).json({ status: 'processing' });

  try {
    // create meeting in partitioned DB and register in Redis
    const meetingId = await createMeetingInShard(req.body);
    const resp = { meetingId, joinUrl: `https://zoom.example/m/${meetingId}` };
    await client.setAsync(cacheKey, JSON.stringify(resp), 'EX', 60 * 60); // cache result
    return res.json(resp);
  } finally {
    await client.delAsync(`lock:${cacheKey}`);
  }
});

